code = """import json, re
from collections import defaultdict

# Get the storage data
children_books = [{"book_id": "bookid_4", "title": "Monstrous Stories #4: The Day the Mice Stood Still"}, {"book_id": "bookid_14", "title": "The Old Man and the Pirate Princess"}, {"book_id": "bookid_32", "title": "The Very Hungry Caterpillar (English and Arabic Edition)"}, {"book_id": "bookid_40", "title": "Egypt (Enchantment of the World)"}, {"book_id": "bookid_48", "title": "Clark the Shark: Tooth Trouble, No. 1"}, {"book_id": "bookid_52", "title": "I Hadn't Meant to Tell You This"}, {"book_id": "bookid_54", "title": "Favorite Thorton W. Burgess Stories: 6 Books"}, {"book_id": "bookid_55", "title": "Behind the Wheel (Choose Your Own Adventure #35)(Paperback/Revised)"}, {"book_id": "bookid_57", "title": "Goodnight Riley and the Moon, It's Almost Bedtime: Personalized Children\u2019s Books, Personalized Gifts, and Bedtime Stories"}, {"book_id": "bookid_96", "title": "Cheer Up, Ben Franklin! (Young Historians)"}, {"book_id": "bookid_99", "title": "Buddy the Soldier Bear"}, {"book_id": "bookid_108", "title": "The Library Book"}, {"book_id": "bookid_111", "title": "Can You Buy Me The Wind?"}, {"book_id": "bookid_116", "title": "From the Earth to the Moon by Jules Verne, Fiction, Fantasy & Magic"}, {"book_id": "bookid_120", "title": "Caroline's Color Dreams"}, {"book_id": "bookid_124", "title": "Skeleton Play: A Fun, Rhyming Halloween Book for Kids! (1)"}, {"book_id": "bookid_130", "title": "Benny Goes To The Moon: The great new book from Top Children's entertainer Gerry Ogilvie"}, {"book_id": "bookid_132", "title": "Mae and Jane in the Rain"}, {"book_id": "bookid_145", "title": "Kirsten: An American Girl : 1854 (The American Girls Collection Boxed Set)"}, {"book_id": "bookid_146", "title": "LunaLu the Llamacorn"}, {"book_id": "bookid_149", "title": "Trouble in the CTC!: The Terra Prime Adventures Book 2"}, {"book_id": "bookid_152", "title": "Around the World Mazes"}, {"book_id": "bookid_158", "title": "Cleo Porter and the Body Electric"}, {"book_id": "bookid_163", "title": "Monster Kisses"}, {"book_id": "bookid_170", "title": "Pokemon: Sun & Moon, Vol. 8 (8)"}]

# Try to open the reviews file
file_path = "/tmp/tmpn9d5z9r6.json"
with open(file_path, 'r') as f:
    review_data = json.load(f)

# Process the data
book_titles = {b['book_id']: b['title'] for b in children_books}
ratings = defaultdict(list)

for review in review_data:
    pid = review['purchase_id']
    m = re.search(r'purchaseid_(\d+)', pid)
    if m:
        bid = 'bookid_' + m.group(1)
        if bid in book_titles:
            ratings[bid].append(float(review['rating']))

# Calculate and filter
results = []
for bid, rate_list in ratings.items():
    avg_rate = sum(rate_list) / len(rate_list)
    if avg_rate >= 4.5:
        results.append([book_titles[bid], round(avg_rate, 2), len(rate_list)])

results.sort(key=lambda x: (-x[1], -x[2]))

# Format output
output = []
if not results:
    output.append("None found")
else:
    output.append("Children books with avg rating 4.5 or higher:")
    for r in results:
        line = "- " + r[0] + " (" + str(r[1]) + ", " + str(r[2]) + " reviews)"
        output.append(line)

result_str = "\n".join(output)
print(result_str)"""

